const ocrResponse = $input.first().json;
let extractedText = "";
let error = null;
try {
  const apiError = ocrResponse.responses?.[0]?.error;
  if (apiError) {
    error = apiError.message || "vision_api_error";
  } else {
    extractedText = (ocrResponse.responses?.[0]?.fullTextAnnotation?.text || ocrResponse.responses?.[0]?.textAnnotations?.[0]?.description || "").trim();
    if (!extractedText) error = "ocr_empty_text";
  }
} catch (e) {
  error = e?.message || "ocr_parse_exception";
}
const prep = $("Prepare Input").first().json;
return [{ json: { batchId: prep.batchId, sourceFileId: prep.sourceFileId, fileUrl: prep.fileUrl, objectKey: prep.objectKey || null, sourceType: prep.sourceType || null, mode: prep.mode || "BENCHMARK", aiConfig: prep.aiConfig || {}, benchmarkReferenceText: prep.benchmarkReferenceText || "", text: extractedText, error } }];

const promptLibrary = {
  "pipe-v5a": { "label": "Dengeleyici / Esnek", "legacyNodeSuffix": "Hizmet Agirlikli Dengeli", "legacyIndex": 0 },
  "pipe-v5b": { "label": "Coklu Hizmet Ayirici", "legacyNodeSuffix": "Hizmet Agirlikli Coklu Hizmet Sert", "legacyIndex": 1 },
  "pipe-v5c": { "label": "Sema Disiplinli", "legacyNodeSuffix": "Hizmet Agirlikli Sema Disiplinli", "legacyIndex": 2 },
  "pipe-v5d": { "label": "Saat/Isim Anchored", "legacyNodeSuffix": null, "legacyIndex": null },
  "pipe-v5e": { "label": "Not Ayrimi Sert", "legacyNodeSuffix": null, "legacyIndex": null }
};
const modelMatrix = [
  { "name": "MiniMax M2.7", "model": "minimax/minimax-m2.7", "startIndex": 1 },
  { "name": "Grok 4.1 Fast", "model": "x-ai/grok-4.1-fast", "startIndex": 4 },
  { "name": "GPT-4o Mini", "model": "openai/gpt-4o-mini", "startIndex": 7 },
  { "name": "Gemini 2.5 Flash Lite", "model": "google/gemini-2.5-flash-lite", "startIndex": 10 },
  { "name": "Gemini 3.0 Flash", "model": "google/gemini-3.0-flash", "startIndex": 13 },
  { "name": "Gemini 3.0 Flash Lite Preview", "model": "google/gemini-3.0-flash-lite-preview", "startIndex": 16 },
  { "name": "Gemini 2.5 Flash", "model": "google/gemini-2.5-flash", "startIndex": 19 }
];
const phaseConfig = {
  PHASE1: {
    promptVersions: ["pipe-v5a", "pipe-v5b", "pipe-v5c", "pipe-v5d", "pipe-v5e"],
    strictnesses: ["OFF"],
    temperatures: [0]
  },
  PHASE2: {
    promptVersions: null,
    strictnesses: ["BALANCED", "STRICT"],
    temperatures: [0]
  },
  PHASE3: {
    promptVersions: null,
    strictnesses: null,
    temperatures: [0, 0.2, 0.4]
  }
};

const source = $("Extract OCR Text").first().json;
const sourceConfig = source.aiConfig || {};
const benchmarkCfg = sourceConfig.benchmark || {};
const phaseRaw = String(source.phase || benchmarkCfg.phase || sourceConfig.phase || "PHASE1").toUpperCase();
const phase = phaseConfig[phaseRaw] ? phaseRaw : "PHASE1";

function trimText(v) { return typeof v === "string" ? v.trim() : ""; }
function nullable(v) { const x = trimText(v); return !x || x.toLowerCase() === "null" ? null : x; }
function normalizeTime(v) {
  const x = trimText(v);
  if (!x || x.toLowerCase() === "null") return null;
  let m = x.match(/^(\d{1,2})[:.](\d{2})$/);
  if (m) {
    const hour = Number(m[1]);
    const minute = Number(m[2]);
    if (hour >= 0 && hour <= 23 && minute >= 0 && minute <= 59) return String(hour).padStart(2, "0") + ":" + String(minute).padStart(2, "0");
  }
  m = x.match(/^(\d{2})(\d{2})$/);
  if (m) {
    const hour = Number(m[1]);
    const minute = Number(m[2]);
    if (hour >= 0 && hour <= 23 && minute >= 0 && minute <= 59) return String(hour).padStart(2, "0") + ":" + String(minute).padStart(2, "0");
  }
  return null;
}
function normalizeDate(v) {
  const x = trimText(v);
  if (!x || x.toLowerCase() === "null") return null;
  let m = x.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{2,4})$/);
  if (m) {
    let year = Number(m[3]);
    if (year < 100) year += 2000;
    return String(Number(m[1])).padStart(2, "0") + "." + String(Number(m[2])).padStart(2, "0") + "." + String(year).padStart(4, "0");
  }
  if (/^(\d{4})-(\d{2})-(\d{2})$/.test(x)) return x;
  return null;
}
function normalizeNumber(v) {
  if (v === null || v === undefined || v === "") return null;
  const n = Number(String(v).replace(",", "."));
  return Number.isFinite(n) ? n : null;
}
function unwrapJson(raw) {
  const text = trimText(raw);
  if (!text) throw new Error("llm_empty_output");
  try { return JSON.parse(text); } catch (error) {}
  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) return JSON.parse(fenced[1].trim());
  const start = text.indexOf("{");
  const end = text.lastIndexOf("}");
  if (start !== -1 && end > start) return JSON.parse(text.slice(start, end + 1));
  throw new Error("llm_invalid_json");
}
function normalizeRows(payload) {
  const rows = Array.isArray(payload) ? payload : (Array.isArray(payload?.rows) ? payload.rows : []);
  return rows.map((row, index) => ({
    rowIndex: Number(row?.rowIndex) > 0 ? Number(row.rowIndex) : index + 1,
    customerName: nullable(row?.customerName || row?.name || row?.customer || row?.customerNameRaw || row?.clientName || row?.client),
    customerPhoneRaw: nullable(row?.customerPhoneRaw || row?.phoneRaw || row?.phone),
    appointmentDate: normalizeDate(row?.appointmentDate || row?.date || row?.appointment_date),
    startTime: normalizeTime(row?.startTime || row?.time || row?.hour || row?.start),
    endTime: normalizeTime(row?.endTime || row?.end || row?.finishTime),
    durationMinutes: normalizeNumber(row?.durationMinutes),
    serviceNameRaw: nullable(row?.serviceNameRaw || row?.servicesNormalized || row?.service || row?.serviceRaw || row?.services || row?.serviceName),
    staffNameRaw: nullable(row?.staffNameRaw || row?.staff),
    priceRaw: normalizeNumber(row?.priceRaw),
    notesRaw: nullable(row?.notesRaw || row?.note || row?.notes),
    confidence: (() => {
      const value = Number(row?.confidence);
      if (!Number.isFinite(value)) return 0.5;
      return Math.max(0, Math.min(1, value));
    })(),
  })).filter((row) => row.appointmentDate || row.startTime || row.customerName || row.serviceNameRaw || row.notesRaw);
}

const finalistPrompts = Array.isArray(benchmarkCfg.finalistPromptVersions) && benchmarkCfg.finalistPromptVersions.length
  ? benchmarkCfg.finalistPromptVersions
  : (Array.isArray(benchmarkCfg.promptVersions) && benchmarkCfg.promptVersions.length ? benchmarkCfg.promptVersions : null);
const finalistStrictnesses = Array.isArray(benchmarkCfg.strictnesses) && benchmarkCfg.strictnesses.length ? benchmarkCfg.strictnesses : null;
const finalistTemperatures = Array.isArray(benchmarkCfg.temperatures) && benchmarkCfg.temperatures.length ? benchmarkCfg.temperatures : null;

const promptVersions = (phaseConfig[phase].promptVersions || finalistPrompts || ["pipe-v5a", "pipe-v5b"]).filter((v) => promptLibrary[v]);
const strictnesses = (phaseConfig[phase].strictnesses || finalistStrictnesses || ["BALANCED"]).map((v) => String(v).toUpperCase());
const temperatures = (phaseConfig[phase].temperatures || finalistTemperatures || [0]).map((v) => Number(v)).filter((v) => Number.isFinite(v));

const candidates = [];
let missingNodeCount = 0;
for (const modelEntry of modelMatrix) {
  for (const promptVersion of promptVersions) {
    const promptMeta = promptLibrary[promptVersion] || {};
    for (const strictness of strictnesses) {
      for (const temperature of temperatures) {
        const canReadLegacy = Number(promptMeta.legacyIndex) >= 0 && temperature === 0 && (phase === "PHASE1" || strictness === "OFF" || strictness === "BALANCED");
        let rawOutputText = "";
        let parsedRows = [];
        if (canReadLegacy) {
          const chainNumber = modelEntry.startIndex + Number(promptMeta.legacyIndex);
          const nodeName = "Chain " + chainNumber + " - " + modelEntry.name + " / " + promptMeta.legacyNodeSuffix;
          try {
            const nodeJson = $item(0).$node[nodeName].json || {};
            rawOutputText = trimText(nodeJson.text || "");
            parsedRows = normalizeRows(unwrapJson(rawOutputText));
          } catch (error) {
            missingNodeCount += 1;
            rawOutputText = "ERROR: " + (error?.message || "candidate_read_failed");
            parsedRows = [];
          }
        } else {
          missingNodeCount += 1;
          rawOutputText = "SKIPPED: workflow chain not configured for this phase/prompt/temp/strictness combo";
          parsedRows = [];
        }
        candidates.push({
          provider: "openrouter",
          model: modelEntry.model,
          promptVersion,
          promptLabel: promptMeta.label || promptVersion,
          phase,
          strictness,
          temperature,
          rawOutputText,
          parsedRows
        });
      }
    }
  }
}

const successCount = candidates.filter((candidate) => Array.isArray(candidate.parsedRows) && candidate.parsedRows.length > 0).length;
return [{
  json: {
    batchId: source.batchId,
    sourceFileId: source.sourceFileId,
    mode: "BENCHMARK",
    phase,
    strictness: strictnesses.length === 1 ? strictnesses[0] : null,
    temperature: temperatures.length === 1 ? temperatures[0] : null,
    candidates,
    audit: {
      ocrProvider: "google-vision",
      ocrModel: "DOCUMENT_TEXT_DETECTION",
      ocrRawText: source.text || "",
      activeConfigSnapshot: source.aiConfig || {},
      benchmarkReferenceText: source.benchmarkReferenceText || "",
      metrics: {
        benchmarkReferenceText: source.benchmarkReferenceText || "",
        phase,
        candidateCount: candidates.length,
        modelCount: modelMatrix.length,
        promptCount: promptVersions.length,
        strictnessCount: strictnesses.length,
        temperatureCount: temperatures.length,
        successCount,
        failureCount: candidates.length - successCount,
        expectedCandidateCount: modelMatrix.length * promptVersions.length * strictnesses.length * temperatures.length,
        missingNodeCount
      }
    }
  }
}];
